#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=1e5+5;
int n,m,ss=LLONG_MAX,dp,a[maxn],b[maxn];
signed main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		cin>>a[i]>>b[i];
		ss=min(ss,a[i]+b[i]);
	}
	sort(a+1,a+1+n);
	for(int i=0;i<=n;i++){
		m-=a[i];
		if(m<0){
			break;
		}
		dp=max(dp,i+m/ss*2);
	}
	cout<<dp;
	return 0;
}
